const helmet = require('helmet');
const cors = require('cors');
const rateLimit = require('express-rate-limit');

const app = express();

app.disable('x-powered-by');
app.use(helmet());
app.use(cors({ origin: ['https://your-frontend.example'] }));
app.use(express.json({ limit: '100kb' }));
app.use(rateLimit({ windowMs: 60_000, max: 60 }));

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', /* requireAuth, */ (_req, res) => {
  res.json([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]);
});

app.use((err, _req, res, _next) => {
  res.status(500).json({ error: 'internal_error' });
});

module.exports = app;
```

## Priority order

1. Remove `email` from `/users` or put it behind auth (#3).
2. Add `helmet` + disable `x-powered-by` (#1).
3. Add rate limiting (#2).
4. Decide public vs. internal and bind accordingly (#4).
5. Add global error handler + structured logging (#6).
6. Split `listen` into `server.js` (#9).
7. Add validation library now, before the first input route lands (#8).

