app.use(morgan('combined'));

// Central error handler — prevents stack-trace leakage
app.use((err, req, res, _next) => {
  console.error(err);
  res.status(500).json({ error: 'internal_error' });
});
```

### 6. A05 – Hard-coded port and no TLS termination awareness
