});

const listUsersQuery = z.object({
  limit: z.coerce.number().int().min(1).max(100).default(20),
});

app.get('/users',
  rateLimit({ windowMs: 60_000, max: 30, standardHeaders: true, legacyHeaders: false }),
  requireAuth,
  (req, res) => {
    const parsed = listUsersQuery.safeParse(req.query);
    if (!parsed.success) return res.status(400).json({ error: 'bad_request' });
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob',   email: 'bob@example.com'   },
    ].slice(0, parsed.data.limit);
    const project = req.user.scope === 'admin'
      ? u => ({ id: u.id, name: u.name, email: u.email })
      : u => ({ id: u.id, name: u.name });
    res.json(users.map(project));
  },
);

app.use((err, req, res, _next) => {
  req.log?.error({ err }, 'unhandled');
  res.status(err.status || 500).json({ error: 'internal_error' });
});

const server = app.listen(Number(process.env.PORT) || 3000, process.env.HOST || '127.0.0.1', () => {
  logger.info({ addr: server.address() }, 'listening');
